import { MpSdk, ConnectOptions } from './sdk';
export { MpSdk };

export interface SetupSdkOptions {
  /**
   * Array of options to pass on SDK connection
   */
  connectOptions?: ConnectOptions;
  /**
   * The element or selector that will attach the created iframe.
   * Defaults to document.body if not specified. Ignored if the `iframe` option is provided.
   */
  container?: string | HTMLElement;
  /**
   * The domain to connect to. Defaults to `my.matterport.com`.
   */
  // autocomplete to given literals or any string: https://github.com/microsoft/TypeScript/issues/29729#issuecomment-567871939
  // eslint-disable-next-line
  domain?: ('my.matterport.com' | 'my.matterportvr.cn') | (string & {});
  /**
   * The element or selector to use as the iframe for space display.
   * Creates a new iframe if falsy. Default `undefined`.
   */
  iframe?: string | HTMLIFrameElement;
  /**
   * The options to pass to the iframe, as an object of attribute keys and values.
   *
   * ```
   * { width: '500px', height: '500px' }
   * // creates: <iframe width="500px" height="500px">
   * ```
   */
  iframeAttributes?: Record<string, any>;
  /**
   * The query params to include in the iframe's `src` URL. See https://support.matterport.com/s/article/URL-Parameters
   * for a full list.
   *
   * Do not specify the `m` param in these params - use the `space` option instead.
   *
   * ```
   * { qs: 1 }
   * // creates: <iframe src="...&qs=1">
   * ```
   */
  iframeQueryParams?: Record<string, string | number | boolean> | URLSearchParams;
  /**
   * Space ID. Defaults to an example if not specified.
   */
  space?: string;
}

/**
 * Loads the SDK script, attaches/creates required DOM elements, and loads the desired model.
 * @param sdkKey The SDK key.
 * @param options Options to pass to the SDK scaffolding.
 * @returns A Promise with the created SDK instance.
 */
export function setupSdk(
  sdkKey: string,
  options?: SetupSdkOptions
): Promise<MpSdk>;
